CREATE TABLE sys_dept (
  dept_id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  parent_id bigint DEFAULT 0,
  ancestors varchar(50) DEFAULT '',
  dept_name varchar(30) DEFAULT '',
  order_num int DEFAULT 0,
  leader varchar(20),
  phone varchar(11),
  email varchar(50),
  status char(1) DEFAULT '0',
  del_flag char(1) DEFAULT '0',
  create_by varchar(64) DEFAULT '',
  create_time timestamp,
  update_by varchar(64) DEFAULT '',
  update_time timestamp
);

CREATE TABLE sys_user (
  user_id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  dept_id bigint,
  user_name varchar(30) NOT NULL,
  nick_name varchar(30) NOT NULL,
  user_type varchar(2) DEFAULT '00',
  email varchar(50) DEFAULT '',
  phonenumber varchar(11) DEFAULT '',
  sex char(1) DEFAULT '0',
  avatar varchar(100) DEFAULT '',
  password varchar(100) DEFAULT '',
  status char(1) DEFAULT '0',
  del_flag char(1) DEFAULT '0',
  login_ip varchar(128) DEFAULT '',
  login_date timestamp,
  pwd_update_date timestamp,
  create_by varchar(64) DEFAULT '',
  create_time timestamp,
  update_by varchar(64) DEFAULT '',
  update_time timestamp,
  remark varchar(500)
);
CREATE INDEX idx_sys_user_user_name ON sys_user(user_name);
CREATE INDEX idx_sys_user_dept_id ON sys_user(dept_id);

CREATE TABLE sys_post (
  post_id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  post_code varchar(64) NOT NULL,
  post_name varchar(50) NOT NULL,
  post_sort int NOT NULL,
  status char(1) NOT NULL,
  create_by varchar(64) DEFAULT '',
  create_time timestamp,
  update_by varchar(64) DEFAULT '',
  update_time timestamp,
  remark varchar(500)
);

CREATE TABLE sys_role (
  role_id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  role_name varchar(30) NOT NULL,
  role_key varchar(100) NOT NULL,
  role_sort int NOT NULL,
  data_scope char(1) DEFAULT '1',
  menu_check_strictly boolean DEFAULT true,
  dept_check_strictly boolean DEFAULT true,
  status char(1) NOT NULL,
  del_flag char(1) DEFAULT '0',
  create_by varchar(64) DEFAULT '',
  create_time timestamp,
  update_by varchar(64) DEFAULT '',
  update_time timestamp,
  remark varchar(500)
);

CREATE TABLE sys_menu (
  menu_id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  menu_name varchar(50) NOT NULL,
  parent_id bigint DEFAULT 0,
  order_num int DEFAULT 0,
  path varchar(200) DEFAULT '',
  component varchar(255),
  query varchar(255),
  route_name varchar(50) DEFAULT '',
  is_frame varchar(1) DEFAULT '1',
  is_cache varchar(1) DEFAULT '0',
  menu_type char(1) DEFAULT '',
  visible char(1) DEFAULT '0',
  status char(1) DEFAULT '0',
  perms varchar(100),
  icon varchar(100) DEFAULT '#',
  create_by varchar(64) DEFAULT '',
  create_time timestamp,
  update_by varchar(64) DEFAULT '',
  update_time timestamp,
  remark varchar(500) DEFAULT ''
);
CREATE INDEX idx_sys_menu_parent_id ON sys_menu(parent_id);

CREATE TABLE sys_user_role (
  user_role_id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  user_id bigint NOT NULL,
  role_id bigint NOT NULL,
  UNIQUE (user_id, role_id)
);

CREATE TABLE sys_role_menu (
  role_menu_id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  role_id bigint NOT NULL,
  menu_id bigint NOT NULL,
  UNIQUE (role_id, menu_id)
);

CREATE TABLE sys_role_dept (
  role_dept_id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  role_id bigint NOT NULL,
  dept_id bigint NOT NULL,
  UNIQUE (role_id, dept_id)
);

CREATE TABLE sys_user_post (
  user_post_id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  user_id bigint NOT NULL,
  post_id bigint NOT NULL,
  UNIQUE (user_id, post_id)
);

CREATE TABLE sys_oper_log (
  oper_id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  title varchar(50) DEFAULT '',
  business_type int DEFAULT 0,
  method varchar(200) DEFAULT '',
  request_method varchar(10) DEFAULT '',
  operator_type int DEFAULT 0,
  oper_name varchar(50) DEFAULT '',
  dept_name varchar(50) DEFAULT '',
  oper_url varchar(255) DEFAULT '',
  oper_ip varchar(128) DEFAULT '',
  oper_location varchar(255) DEFAULT '',
  oper_param text,
  json_result text,
  status int DEFAULT 0,
  error_msg text,
  oper_time timestamp,
  cost_time bigint DEFAULT 0
);
CREATE INDEX idx_sys_oper_log_bt ON sys_oper_log(business_type);
CREATE INDEX idx_sys_oper_log_s ON sys_oper_log(status);
CREATE INDEX idx_sys_oper_log_ot ON sys_oper_log(oper_time);

CREATE TABLE sys_dict_type (
  dict_id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  dict_name varchar(100) DEFAULT '',
  dict_type varchar(100) DEFAULT '',
  status char(1) DEFAULT '0',
  create_by varchar(64) DEFAULT '',
  create_time timestamp,
  update_by varchar(64) DEFAULT '',
  update_time timestamp,
  remark varchar(500),
  UNIQUE (dict_type)
);

CREATE TABLE sys_dict_data (
  dict_code bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  dict_sort bigint DEFAULT 0,
  dict_label varchar(100) DEFAULT '',
  dict_value varchar(100) DEFAULT '',
  dict_type varchar(100) DEFAULT '',
  css_class varchar(100),
  list_class varchar(100),
  is_default char(1) DEFAULT 'N',
  status char(1) DEFAULT '0',
  create_by varchar(64) DEFAULT '',
  create_time timestamp,
  update_by varchar(64) DEFAULT '',
  update_time timestamp,
  remark varchar(500)
);

CREATE TABLE sys_config (
  config_id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  config_name varchar(100) DEFAULT '',
  config_key varchar(100) DEFAULT '',
  config_value varchar(500) DEFAULT '',
  config_type char(1) DEFAULT 'N',
  create_by varchar(64) DEFAULT '',
  create_time timestamp,
  update_by varchar(64) DEFAULT '',
  update_time timestamp,
  remark varchar(500)
);

CREATE TABLE sys_logininfor (
  info_id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  user_name varchar(50) DEFAULT '',
  status char(1) DEFAULT '0',
  ipaddr varchar(128) DEFAULT '',
  login_location varchar(255) DEFAULT '',
  browser varchar(50) DEFAULT '',
  os varchar(50) DEFAULT '',
  msg varchar(255) DEFAULT '',
  login_time timestamp
);
CREATE INDEX idx_sys_logininfor_s ON sys_logininfor(status);
CREATE INDEX idx_sys_logininfor_lt ON sys_logininfor(login_time);

CREATE TABLE sys_job (
  job_id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  job_name varchar(64) DEFAULT '',
  job_group varchar(64) DEFAULT 'DEFAULT',
  invoke_target varchar(500) NOT NULL,
  cron_expression varchar(255) DEFAULT '',
  misfire_policy varchar(20) DEFAULT '3',
  concurrent char(1) DEFAULT '1',
  status char(1) DEFAULT '0',
  create_by varchar(64) DEFAULT '',
  create_time timestamp,
  update_by varchar(64) DEFAULT '',
  update_time timestamp,
  remark varchar(500) DEFAULT ''
);
CREATE UNIQUE INDEX uk_sys_job_name_group ON sys_job(job_id, job_name, job_group);

CREATE TABLE sys_job_log (
  job_log_id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  job_name varchar(64) NOT NULL,
  job_group varchar(64) NOT NULL,
  invoke_target varchar(500) NOT NULL,
  job_message varchar(500),
  status char(1) DEFAULT '0',
  exception_info text DEFAULT '',
  create_time timestamp,
  start_time timestamp,
  stop_time timestamp
);

CREATE TABLE sys_notice (
  notice_id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  notice_title varchar(50) NOT NULL,
  notice_type char(1) NOT NULL,
  notice_content text,
  status char(1) DEFAULT '0',
  create_by varchar(64) DEFAULT '',
  create_time timestamp,
  update_by varchar(64) DEFAULT '',
  update_time timestamp,
  remark varchar(255)
);

CREATE TABLE gen_table (
  table_id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  table_name varchar(200) DEFAULT '',
  table_comment varchar(500) DEFAULT '',
  sub_table_name varchar(64),
  sub_table_fk_name varchar(64),
  class_name varchar(100) DEFAULT '',
